{
var seed = GetInt(parameters, "seed", context.Seed);
var runeStyle = GetChoice(parameters, "runeStyle", "norse");
var glowStrength = GetFloat(parameters, "glowStrength", 0.5f);
var runeColor = GetColor(parameters, "color", System.Windows.Media.Color.FromRgb(60, 100, 220));
var opacity = GetFloat(parameters, "opacity", 0.9f);
var sizeParam = GetFloat(parameters, "size", 0.9f);
var thickness = GetFloat(parameters, "thickness", 0.12f);
var rotation = GetFloat(parameters, "rotation", 0f) * MathF.PI / 180f;

var size = context.TileSize;
var half = size * 0.5f;
var maxR = half * sizeParam * 1.414f;
var thickPx = Math.Max(1f, thickness * size);
var cosR = MathF.Cos(rotation);
var sinR = MathF.Sin(rotation);

var rng = new System.Random(seed);
var r2 = rng.NextDouble();
var r3 = rng.NextDouble();

// Style parameters (may be overridden by runeStyle switch)
var pts = 5 + (int)(r2 * 4);
var twist = (float)(r3 * 0.3 + 0.1);
var innerRatio = (float)(0.3 + rng.NextDouble() * 0.4);
var spike = (float)(0.5 + rng.NextDouble() * 1.5);
var morph = (float)(0.3 + rng.NextDouble() * 0.7);
var jx = 0.0f; var jy = 0.0f;

switch (runeStyle)
{
    case "magic":
        jx = 0.7885f * (float)(rng.NextDouble() * 0.3 - 0.15);
        jy = 0.7885f * (float)(rng.NextDouble() * 0.3 - 0.15);
        pts = 7; spike = 1.8f; morph = 0.8f;
        break;
    case "ancient":
        jx = 0.35f; jy = 0.35f;
        pts = 4; spike = 0.6f; morph = 0.3f;
        break;
    case "holy":
        jx = 0.0f; jy = 0.8f;
        pts = 8; spike = 1.2f; morph = 0.5f;
        break;
    default: // norse
        jx = 0.4f; jy = 0.6f;
        pts = 3; spike = 1.0f; morph = 0.4f;
        break;
}

var result = new PixelBuffer(size, size);

var cR = runeColor.R / 255f;
var cG = runeColor.G / 255f;
var cB = runeColor.B / 255f;

float SuperShape(float theta, float n1, float n2, float n3, float m)
{
    var t = theta * m / 4f;
    var p1 = MathF.Pow(MathF.Abs(MathF.Cos(t)), n2);
    var p2 = MathF.Pow(MathF.Abs(MathF.Sin(t)), n3);
    var rVal = MathF.Pow(p1 + p2, -1f / n1);
    return float.IsFinite(rVal) ? rVal : 0f;
}

result.ParallelForEachPixel((x, y) =>
{
    var nx = (x + 0.5f) / size * 2f - 1f;
    var ny = (y + 0.5f) / size * 2f - 1f;

    // Apply rotation
    if (MathF.Abs(rotation) > 0.001f)
    {
        var rnx = nx * cosR - ny * sinR;
        var rny = nx * sinR + ny * cosR;
        nx = rnx; ny = rny;
    }

    var r = MathF.Sqrt(nx * nx + ny * ny);
    var theta = MathF.Atan2(ny, nx);

    // Supershape outer boundary
    var ss = SuperShape(theta, 1f + morph * 2f, 0.5f + spike * 0.5f, 0.5f + spike * 0.5f, pts);
    var ssR = ss * maxR;

    // Supershape inner hole
    var ssInner = SuperShape(theta + twist, 0.8f + morph, 0.8f, 0.8f, pts + 1);
    var innerR = ssInner * maxR * innerRatio;

    // Radial harmonic waves (organic detail)
    var waves = MathF.Sin(r * 20f + theta * 3f) * 0.3f +
                MathF.Sin(r * 13f - theta * 5f) * 0.2f +
                MathF.Sin(r * 7f * (1f + morph)) * 0.2f;

    // Angular spike ornamentation
    var spikesVal = MathF.Pow(MathF.Abs(MathF.Cos(theta * pts * 0.5f)), 0.3f + spike * 0.5f);
    var spikeField = MathF.Max(0f, spikesVal - r / maxR * 0.5f);

    // Core glyph: subtractive synthesis
    var outerDist = r / (ssR + 0.001f);
    var innerDist = r / (innerR + 0.001f);
    var field = MathF.Max(0f, 1f - outerDist);
    field = MathF.Max(0f, field - MathF.Max(0f, 1f - innerDist) * 0.8f);
    field = MathF.Max(field, spikeField * 0.6f);

    // Julia detail for magic/holy
    if (runeStyle == "magic" || runeStyle == "holy")
    {
        var zx = nx * 0.5f; var zy = ny * 0.5f;
        float julia = 0f;
        for (var i = 0; i < 32; i++)
        {
            var zx2 = zx * zx - zy * zy + jx;
            var zy2 = 2f * zx * zy + jy;
            zx = zx2; zy = zy2;
            if (zx * zx + zy * zy > 4f) { julia = i / 32f; break; }
        }
        field += julia * 0.2f * MathF.Max(0f, 1f - r);
    }

    // Wave detail
    field += waves * 0.15f * MathF.Max(0f, 1f - r / maxR);

    // Edge fade
    field *= Math.Clamp(1f - (r - maxR * 0.85f) / (maxR * 0.15f + 0.001f), 0f, 1f);
    field = Math.Clamp(field, 0f, 1f);

    // Anti-aliased line rendering
    var lineAA = Math.Clamp(1f - MathF.Abs(field - 0.45f) * 6f / thickPx, 0f, 1f);
    var alpha = field > 0.01f ? lineAA * opacity : 0f;

    // Glow
    var glow = 0f;
    if (field < 0.45f && glowStrength > 0.01f)
        glow = MathF.Max(0f, 1f - field / 0.45f) * glowStrength * (1f - lineAA) * 0.5f;

    var finalR = cR * lineAA + glow;
    var finalG = cG * lineAA + glow * 0.8f;
    var finalB = cB * lineAA + glow * 1.2f;

    result.SetPixel(x, y, Math.Clamp(finalR, 0, 1), Math.Clamp(finalG, 0, 1), Math.Clamp(finalB, 0, 1), Math.Clamp(alpha + glow * 0.5f, 0, 1));
});

return result;
}
